import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Trash2, Upload, PencilLine, Save, Plus } from 'lucide-react';
import toast from 'react-hot-toast';

const Admin = () => {
  const [products, setProducts] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    price: '',
    category: 'Gifts',
    description: ''
  });
  const [image, setImage] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/products');
      setProducts(response.data);
    } catch (error) {
      console.error('Error fetching products:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const isEditing = Boolean(selectedProduct);

    if (!isEditing && !image) {
      toast.error('Please select an image');
      return;
    }

    setLoading(true);
    const formDataToSend = new FormData();
    formDataToSend.append('name', formData.name);
    formDataToSend.append('price', formData.price);
    formDataToSend.append('category', formData.category);
    formDataToSend.append('description', formData.description);
    if (image) {
      formDataToSend.append('image', image);
    }

    try {
      if (isEditing) {
        await axios.put(`http://localhost:5000/api/products/${selectedProduct._id}`, formDataToSend, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Product updated successfully!');
      } else {
        await axios.post('http://localhost:5000/api/products', formDataToSend, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Product added successfully!');
      }
      setFormData({ name: '', price: '', category: 'Gifts', description: '' });
      setImage(null);
      setSelectedProduct(null);
      fetchProducts();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save product');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (productId) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`http://localhost:5000/api/products/${productId}`);
        toast.success('Product deleted');
        if (selectedProduct?._id === productId) {
          setSelectedProduct(null);
        }
        fetchProducts();
      } catch (error) {
        toast.error('Failed to delete product');
      }
    }
  };

  const startEdit = (product) => {
    setSelectedProduct(product);
    setFormData({
      name: product.name,
      price: product.price,
      category: product.category,
      description: product.description || ''
    });
    setImage(null);
  };

  const resetForm = () => {
    setSelectedProduct(null);
    setFormData({ name: '', price: '', category: 'Gifts', description: '' });
    setImage(null);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="admin-header mb-8">
        <div>
          <p className="text-sm uppercase tracking-[0.3em] text-rose-600">Control center</p>
          <h1 className="text-3xl font-bold text-slate-800 mt-2">Admin Dashboard</h1>
        </div>
        <button onClick={resetForm} className="btn-secondary">
          <Plus size={16} className="inline mr-2" />
          New item
        </button>
      </div>
      
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="dashboard-panel">
          <h2 className="panel-title">{selectedProduct ? 'Edit Product' : 'Add New Product'}</h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Product Name</label>
              <input
                type="text"
                name="name"
                required
                className="input-field"
                value={formData.name}
                onChange={handleChange}
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Price (€)</label>
              <input
                type="number"
                name="price"
                required
                step="0.01"
                className="input-field"
                value={formData.price}
                onChange={handleChange}
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
              <select
                name="category"
                className="input-field"
                value={formData.category}
                onChange={handleChange}
              >
                <option value="Gifts">Gifts</option>
                <option value="Keychains">Keychains</option>
                <option value="Decorations">Decorations</option>
                <option value="Accessories">Accessories</option>
                <option value="Apparel">Apparel</option>
              </select>
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Description (optional)</label>
              <textarea
                name="description"
                rows="3"
                className="input-field"
                value={formData.description}
                onChange={handleChange}
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Product Image {selectedProduct ? '(leave empty to keep current)' : ''}</label>
              <input
                type="file"
                accept="image/*"
                onChange={(e) => setImage(e.target.files[0])}
                className="w-full text-slate-700"
                required={!selectedProduct}
              />
            </div>
            
            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full flex items-center justify-center gap-2"
            >
              {selectedProduct ? <Save size={18} /> : <Upload size={18} />}
              {loading ? 'Saving...' : selectedProduct ? 'Save Changes' : 'Add Product'}
            </button>
          </form>
        </div>
        
        <div className="dashboard-panel">
          <h2 className="panel-title">Manage Products</h2>
          <p className="panel-subtitle">Select any item to edit it instantly.</p>
          <div className="space-y-3 max-h-[32rem] overflow-y-auto pr-1">
            {products.map(product => (
              <div key={product._id} className={`flex items-center gap-4 p-3 border rounded-2xl ${selectedProduct?._id === product._id ? 'border-amber-300 bg-amber-50/20' : 'border-white/10 bg-white/5'}`}>
                <img
                  src={`http://localhost:5000${product.image}`}
                  alt={product.name}
                  className="w-16 h-16 object-cover rounded"
                />
                <div className="flex-1">
                  <h3 className="font-semibold text-slate-800">{product.name}</h3>
                  <p className="text-sm text-slate-700">€{product.price}</p>
                  <p className="text-xs text-rose-600">{product.category}</p>
                </div>
                <button
                  onClick={() => startEdit(product)}
                  className="text-rose-400 hover:text-rose-500 transition"
                >
                  <PencilLine size={18} />
                </button>
                <button
                  onClick={() => handleDelete(product._id)}
                  className="text-sky-400 hover:text-sky-500 transition"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
            {products.length === 0 && (
              <p className="text-slate-700 text-center py-4">No products yet. Add your first product!</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Admin;
